import requests

def test_unauthenticated_delete_org_announcement_returns_401(
    existing_announcement_id, # <fixture>
    base_url,                 # <fixture>
):
    url = f"{base_url}/api/org-announcements/{existing_announcement_id}"

    resp = requests.delete(url)  # no auth header

    assert resp.status_code == 401, (
        f"Expected 401, got {resp.status_code}: {resp.text}"
    )

import requests

def test_forbidden_role_delete_org_announcement_returns_403(
    viewer_auth_token,        # <fixture>
    existing_announcement_id, # <fixture>
    base_url,                 # <fixture>
):
    url = f"{base_url}/api/org-announcements/{existing_announcement_id}"
    headers = {"Authorization": f"Bearer {viewer_auth_token}"}

    resp = requests.delete(url, headers=headers)

    assert resp.status_code == 403, (
        f"Expected 403, got {resp.status_code}: {resp.text}"
    )

import requests

def test_delete_org_announcement_missing_id_returns_400(
    admin_auth_token, # <fixture>
    base_url,         # <fixture>
):
    # Omit the id segment entirely – hits the boundary of mandatory field
    url = f"{base_url}/api/org-announcements/"
    headers = {"Authorization": f"Bearer {admin_auth_token}"}

    resp = requests.delete(url, headers=headers)

    assert resp.status_code in (400, 404), (
        f"Expected 400 or 404 for missing id, got {resp.status_code}: {resp.text}"
    )
